mapper.select:
SELECT id, name, plan, credit
FROM users
WHERE id = #{userId}

mapper.update:
UPDATE dashboard_todo
SET done = #{done},
    completed_at = CASE WHEN #{done} THEN NOW() ELSE NULL END
WHERE id = #{todoId}
  AND user_id = #{userId}
  AND derived_key IS NULL

mapper.delete:
DELETE FROM dashboard_todo
WHERE id = #{todoId}
  AND user_id = #{userId}
  AND derived_key IS NULL
